(function(){var body=document.body;var header=document.querySelector(".site-header--luxury");var menu=document.getElementById("site-mobile-menu");var search=document.getElementById("site-mobile-search");var contact=document.getElementById("site-contact-modal");var desktopBreakpoint=1024;var lastScrollY=window.scrollY||window.pageYOffset||0;var ticking=false;var isMobileViewport=function(){return window.innerWidth<=desktopBreakpoint};var setExpanded=function(selector,isOpen){document.querySelectorAll(selector).forEach(function(trigger){trigger.setAttribute("aria-expanded",isOpen?"true":"false")})};var syncBodyState=function(){var hasOpen=(menu&&menu.classList.contains("is-open"))||(search&&search.classList.contains("is-open"))||(contact&&contact.classList.contains("is-open"))||body.classList.contains("site-cart-open");body.classList.toggle("site-mobile-panel-open",!!hasOpen)};var openPanel=function(panel,selector){if(!panel){return}panel.classList.add("is-open");panel.setAttribute("aria-hidden","false");if(selector){setExpanded(selector,true)}syncBodyState()};var closePanel=function(panel,selector){if(!panel){return}panel.classList.remove("is-open");panel.setAttribute("aria-hidden","true");if(selector){setExpanded(selector,false)}syncBodyState()};var updateHeaderState=function(){if(!header){return}if(isMobileViewport()){header.classList.remove("is-scroll-hidden");header.classList.remove("is-scroll-visible");lastScrollY=window.scrollY||window.pageYOffset||0;return}var currentScrollY=window.scrollY||window.pageYOffset||0;if(currentScrollY<=24){header.classList.remove("is-scroll-hidden");header.classList.add("is-scroll-visible");lastScrollY=currentScrollY;return}var delta=currentScrollY-lastScrollY;if(delta>8){header.classList.add("is-scroll-hidden");header.classList.remove("is-scroll-visible")}else if(delta<-8){header.classList.add("is-scroll-visible");header.classList.remove("is-scroll-hidden")}lastScrollY=currentScrollY};var requestHeaderUpdate=function(){if(ticking){return}ticking=true;window.requestAnimationFrame(function(){updateHeaderState();ticking=false})};document.addEventListener("click",function(event){if(event.target.closest("[data-open-mobile-menu]")){event.preventDefault();openPanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]");closePanel(contact,"[data-open-contact-modal]")}if(event.target.closest("[data-close-mobile-menu]")){event.preventDefault();closePanel(menu,"[data-open-mobile-menu]")}if(event.target.closest("[data-open-mobile-search]")){event.preventDefault();openPanel(search,"[data-open-mobile-search]");closePanel(menu,"[data-open-mobile-menu]");closePanel(contact,"[data-open-contact-modal]");var input=search?search.querySelector('input[type="search"]'):null;if(input){window.setTimeout(function(){input.focus()},150)}}if(event.target.closest("[data-close-mobile-search]")){event.preventDefault();closePanel(search,"[data-open-mobile-search]")}if(event.target.closest("[data-open-contact-modal]")){event.preventDefault();openPanel(contact,"[data-open-contact-modal]");closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]")}if(event.target.closest("[data-close-contact-modal]")){event.preventDefault();closePanel(contact,"[data-open-contact-modal]")}});document.addEventListener("keydown",function(event){if(event.key!=="Escape"){return}closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]");closePanel(contact,"[data-open-contact-modal]")});window.addEventListener("resize",function(){if(!isMobileViewport()){closePanel(menu,"[data-open-mobile-menu]");closePanel(search,"[data-open-mobile-search]");closePanel(contact,"[data-open-contact-modal]")}requestHeaderUpdate()});window.addEventListener("scroll",requestHeaderUpdate,{passive:true});syncBodyState();updateHeaderState()})();
